#include <bits/stdc++.h>
using namespace std;
const int mod=2012;
const int N=2005;
int n,dp[N][N],a[N];
string s;
int main()
{
	cin>>s;
	n=s.size();
	s=" "+s;
	for(int i=1;i<=n;i++)
	{
		if(s[i]=='(') a[i]=1;
		else a[i]=-1;
	}
	dp[0][0]=1;
	int sum=0;
	for(int i=1;i<=n;i++)
	{
		sum+=a[i];
		for(int j=0;j<=sum;j++)
		{
			dp[i][j]=dp[i-1][j];
			if(j>=a[i]) dp[i][j]+=dp[i-1][j-a[i]];
			dp[i][j]%=mod;
		}
	}
	cout<<dp[n][0];
	return 0;
}
